+#[cfg(unix)]
+fn firecracker_uid() -> Option<u32> {
+    let output = Command::new("getent")
+        .args(["passwd", FIRECRACKER_USER])
+        .output()
+        .ok()?;
+    if !output.status.success() {
+        return None;
+    }
+    parse_getent_passwd(&String::from_utf8_lossy(&output.stdout)).map(|(uid, _gid)| uid)
