+#[cfg(unix)]
+fn path_readable_by_uid(path: &Path, uid: u32) -> bool {
+    use std::os::unix::fs::MetadataExt;
+
+    let Ok(meta) = std::fs::metadata(path) else {
+        return false;
+    };
+    let mode = meta.mode();
+    if meta.uid() == uid {
+        return mode & 0o400 != 0;
+    }
+    if meta.gid() == current_primary_gid(uid) {
+        return mode & 0o040 != 0;
+    }
+    mode & 0o004 != 0
+}
