+/** Tests for terminal artifact listing timeout helper. */
+
+import { describe, expect, test, vi } from "vitest";
+
+import { captureListedArtifacts, LIST_ARTIFACTS_TIMEOUT_MS } from "./artifacts-capture.js";
+
+describe("captureListedArtifacts", () => {
+  test("returns validated refs on success", async () => {
+    const refs = await captureListedArtifacts(() =>
+      Promise.resolve([{ path: "a.txt", sizeBytes: 1, updatedAt: "2026-01-01T00:00:00.000Z" }]),
+    );
+    expect(refs).toHaveLength(1);
+    expect(refs[0]?.path).toBe("a.txt");
+  });
+
+  test("stalled list resolves to empty after timeout", async () => {
+    vi.useFakeTimers();
+    const promise = captureListedArtifacts(() => new Promise(() => undefined));
+    await vi.advanceTimersByTimeAsync(LIST_ARTIFACTS_TIMEOUT_MS + 1);
+    await expect(promise).resolves.toEqual([]);
+    vi.useRealTimers();
+  });
+
+  test("non-array list resolves to empty", async () => {
+    await expect(captureListedArtifacts(() => Promise.resolve(null))).resolves.toEqual([]);
+  });
+
+  test("drops malformed artifact entries", async () => {
+    const refs = await captureListedArtifacts(() =>
+      Promise.resolve([
+        { path: 123 },
+        { path: "ok.txt", sizeBytes: 1, updatedAt: "2026-01-01T00:00:00.000Z" },
+      ]),
+    );
+    expect(refs).toHaveLength(1);
+    expect(refs[0]?.path).toBe("ok.txt");
+  });
+
+  test("logs timeout via provided logger", async () => {
+    vi.useFakeTimers();
+    const warn = vi.fn();
+    const promise = captureListedArtifacts(() => new Promise(() => undefined), {
+      warn,
+    } as never);
+    await vi.advanceTimersByTimeAsync(LIST_ARTIFACTS_TIMEOUT_MS + 1);
+    await promise;
+    expect(warn).toHaveBeenCalled();
+    vi.useRealTimers();
+  });
+});
diff --git a/packages/agent-runner/src/artifacts-capture.ts b/packages/agent-runner/src/artifacts-capture.ts
new file mode 100644
index 0000000..cd99e55
--- /dev/null
+++ b/packages/agent-runner/src/artifacts-capture.ts
@@ -0,0 +1,72 @@
+/**
+ * Best-effort terminal artifact listing with a timeout so finalize
+ * cannot hang on a stalled provider call.
+ */
+
+import type { Logger } from "@ship/logger";
+
+import { type ArtifactRef, artifactRefSchema } from "@ship/workflow";
+
+/** Best-effort cap on terminal `listArtifacts()` so finalize cannot hang. */
+export const LIST_ARTIFACTS_TIMEOUT_MS = 15_000;
+
+class ListArtifactsTimeoutError extends Error {
+  constructor(timeoutMs: number) {
+    super(`listArtifacts did not complete within ${timeoutMs.toString()}ms`);
+    this.name = "ListArtifactsTimeoutError";
+  }
+}
+
+async function withTimeout<T>(promise: Promise<T>, timeoutMs: number): Promise<T> {
+  let timer: ReturnType<typeof setTimeout> | undefined;
+  try {
+    return await Promise.race([
+      promise,
+      new Promise<T>((_, reject) => {
+        timer = setTimeout(() => {
+          void promise.catch(() => undefined);
+          reject(new ListArtifactsTimeoutError(timeoutMs));
+        }, timeoutMs);
+      }),
+    ]);
+  } finally {
+    if (timer !== undefined) clearTimeout(timer);
+  }
+}
+
+function logListArtifactsFailure(log: Logger | undefined, err: unknown): void {
+  try {
+    const message = err instanceof Error ? err.message : String(err);
+    const label =
+      err instanceof ListArtifactsTimeoutError ? "listArtifacts timed out" : "listArtifacts failed";
+    if (log !== undefined) {
+      log.warn({ label, err: message }, label);
+    }
+  } catch {
+    /* swallow — diagnostic logging must never affect control flow */
+  }
+}
+
+/** Runs `listArtifacts`, logs on failure/timeout, returns refs or `[]`. */
+export async function captureListedArtifacts(
+  listArtifacts: () => Promise<unknown>,
+  log?: Logger,
+): Promise<readonly ArtifactRef[]> {
+  try {
+    const listed = await withTimeout(listArtifacts(), LIST_ARTIFACTS_TIMEOUT_MS);
+    if (!Array.isArray(listed)) return [];
+    return listed.flatMap((a): ArtifactRef[] => {
+      if (typeof a !== "object" || a === null) return [];
+      const rec = a as Record<string, unknown>;
+      const parsed = artifactRefSchema.safeParse({
+        path: rec["path"],
+        sizeBytes: rec["sizeBytes"],
+        updatedAt: rec["updatedAt"],
+      });
+      return parsed.success ? [parsed.data] : [];
+    });
+  } catch (err) {
+    logListArtifactsFailure(log, err);
+    return [];
+  }
+}
