@@ -0,0 +1,264 @@
+/** Table-driven tests for projection-based `classifyFailure` and `buildFailureDetail`. */
+
+import { LOCAL_RUN_CONTENTION_HINT } from "@ship/workflow";
+import { describe, expect, test } from "vitest";
+
+import {
+  buildFailureDetail,
+  classifyFailure,
+  formatClassifiedErrorMessage,
+} from "./classify-failure.js";
+import { testEventProjection } from "./test-projection.js";
+
+const CAP_MS = 30 * 60 * 1000;
+const projection = testEventProjection;
+
+describe("classifyFailure", () => {
+  test("empty events with no signals → unknown", () => {
+    expect(classifyFailure({ events: [], projection })).toBe("unknown");
+  });
+
+  test("isStoreContention → contention (beats thrownError)", () => {
+    expect(
+      classifyFailure({ events: [], isStoreContention: true, projection, thrownError: true }),
+    ).toBe("contention");
+  });
+
+  test("thrownError → sdk-throw", () => {
+    expect(classifyFailure({ events: [], projection, thrownError: true })).toBe("sdk-throw");
+  });
+
+  test("latest failed tool_call → logic", () => {
+    const events = [{ type: "tool_call", status: "failed", name: "grep" }];
+    expect(classifyFailure({ events, projection })).toBe("logic");
+  });
+
+  test("running tool_call near cap → agent-collapse-on-running-tool", () => {
+    const events = [
+      { type: "tool_call", status: "running", name: "shell", ts: "2026-06-01T12:00:00.000Z" },
+      { type: "status", status: "ERROR", ts: "2026-06-01T12:25:00.000Z" },
+    ];
+    expect(
+      classifyFailure({
+        durationMs: 25 * 60 * 1000,
+        events,
+        maxRunDurationMs: CAP_MS,
+        projection,
+      }),
+    ).toBe("agent-collapse-on-running-tool");
+  });
+
+  test("sdkTerminalStatus expired (any case) → timeout-near-cap", () => {
+    expect(classifyFailure({ events: [], projection, sdkTerminalStatus: "EXPIRED" })).toBe(
+      "timeout-near-cap",
+    );
+    expect(classifyFailure({ events: [], projection, sdkTerminalStatus: "expired" })).toBe(
+      "timeout-near-cap",
+    );
+  });
+
+  test("latest failed tool_call → logic (error with result text)", () => {
+    const events = [
+      { type: "tool_call", status: "error", result: "first failure" },
+      { type: "status", status: "ERROR" },
+      { type: "tool_call", status: "failed", result: "latest failure" },
+    ];
+    expect(classifyFailure({ events, projection })).toBe("logic");
+  });
+
+  test("running tool_call without timestamps falls back to durationMs for age", () => {
+    const events = [{ type: "tool_call", status: "running", name: "shell" }];
+    expect(
+      classifyFailure({
+        durationMs: 25 * 60 * 1000,
+        events,
+        maxRunDurationMs: CAP_MS,
+        projection,
+      }),
+    ).toBe("agent-collapse-on-running-tool");
+  });
+
+  test("running tool_call later completed (same call_id) is not agent-collapse", () => {
+    const events = [
+      {
+        type: "tool_call",
+        status: "running",
+        name: "shell",
+        call_id: "c1",
+        ts: "2026-06-01T12:00:00.000Z",
+      },
+      {
+        type: "tool_call",
+        status: "completed",
+        name: "shell",
+        call_id: "c1",
+        ts: "2026-06-01T12:05:00.000Z",
+      },
+    ];
+    expect(
+      classifyFailure({ durationMs: 0.85 * CAP_MS, events, maxRunDurationMs: CAP_MS, projection }),
+    ).toBe("unknown");
+  });
+
+  test("durationMs ≥ 0.95×cap → timeout-near-cap", () => {
+    expect(
+      classifyFailure({
+        durationMs: 0.96 * CAP_MS,
+        events: [],
+        maxRunDurationMs: CAP_MS,
+        projection,
+      }),
+    ).toBe("timeout-near-cap");
+  });
+
+  test("never returns undefined", () => {
+    const category = classifyFailure({ events: [], projection });
+    expect(category).toBeDefined();
+    expect(typeof category).toBe("string");
+  });
+});
+
+describe("buildFailureDetail", () => {
+  test("logic category uses failed tool_call detail", () => {
+    const events = [{ type: "tool_call", status: "error", result: "database is locked" }];
+    expect(buildFailureDetail({ category: "logic", events, projection })).toBe(
+      "database is locked",
+    );
+  });
+
+  test("formatClassifiedErrorMessage prefixes category", () => {
+    expect(formatClassifiedErrorMessage("logic", "make check failed")).toBe(
+      "logic; make check failed",
+    );
+  });
+
+  test("contention uses hint from thrown error when present", () => {
+    const err = new Error(`${LOCAL_RUN_CONTENTION_HINT} (database is locked)`);
+    expect(
+      buildFailureDetail({
+        category: "contention",
+        events: [],
+        projection,
+        thrownErr: err,
+      }),
+    ).toBe(err.message);
+    expect(buildFailureDetail({ category: "contention", events: [], projection })).toBe(
+      LOCAL_RUN_CONTENTION_HINT,
+    );
+  });
+
+  test("logic fallback paths", () => {
+    expect(
+      buildFailureDetail({
+        category: "logic",
+        events: [],
+        projection,
+        rawErrorMessage: "runner message",
+      }),
+    ).toBe("runner message");
+    expect(buildFailureDetail({ category: "logic", events: [], projection })).toBe(
+      "tool_call failed",
+    );
+  });
+
+  test("sdk-throw detail paths", () => {
+    expect(
+      buildFailureDetail({
+        category: "sdk-throw",
+        events: [],
+        projection,
+        thrownErr: new Error("Agent.create failed"),
+      }),
+    ).toBe("Agent.create failed");
+    expect(
+      buildFailureDetail({
+        category: "sdk-throw",
+        events: [],
+        projection,
+        rawErrorMessage: "raw only",
+      }),
+    ).toBe("raw only");
+    expect(buildFailureDetail({ category: "sdk-throw", events: [], projection })).toBe(
+      "SDK error before terminal result",
+    );
+  });
+
+  test("agent-collapse describes the running tool", () => {
+    const events = [
+      {
+        type: "tool_call",
+        status: "running",
+        name: "shell",
+        args: { command: "make check" },
+        ts: "2026-06-01T12:00:00.000Z",
+      },
+      { type: "status", status: "ERROR", ts: "2026-06-01T12:04:12.000Z" },
+    ];
+    const detail = buildFailureDetail({
+      category: "agent-collapse-on-running-tool",
+      durationMs: 252_000,
+      events,
+      maxRunDurationMs: CAP_MS,
+      projection,
+    });
+    expect(detail).toContain("shell 'make check'");
+    expect(detail).toContain("never completed");
+    expect(
+      buildFailureDetail({ category: "agent-collapse-on-running-tool", events: [], projection }),
+    ).toBe("agent stopped with a running tool_call");
+  });
+
+  test("timeout-near-cap detail with and without cap", () => {
+    expect(
+      buildFailureDetail({
+        category: "timeout-near-cap",
+        durationMs: CAP_MS,
+        events: [],
+        maxRunDurationMs: CAP_MS,
+        projection,
+        sdkTerminalStatus: "EXPIRED",
+      }),
+    ).toContain("SDK status expired");
+    expect(
+      buildFailureDetail({
+        category: "timeout-near-cap",
+        durationMs: 60_000,
+        events: [],
+        projection,
+      }),
+    ).toBe("duration 1m");
+  });
+
+  test("unknown detail paths", () => {
+    expect(
+      buildFailureDetail({
+        category: "unknown",
+        events: [],
+        projection,
+        rawErrorMessage: "opaque",
+      }),
+    ).toBe("opaque");
+    expect(
+      buildFailureDetail({
+        category: "unknown",
+        events: [],
+        projection,
+        sdkTerminalStatus: "ERROR",
+      }),
+    ).toBe("SDK status ERROR");
+    expect(buildFailureDetail({ category: "unknown", events: [], projection })).toBe(
+      "no classification signals",
+    );
+  });
+
+  test("buildFailureDetail caps long tool output", () => {
+    const longErr = "x".repeat(600);
+    const detail = buildFailureDetail({
+      category: "logic",
+      events: [{ type: "tool_call", status: "error", result: longErr }],
+      projection,
+    });
+    expect(detail.length).toBe(512);
+    expect(detail.endsWith("...")).toBe(true);
+  });
+});
diff --git a/packages/agent-runner/src/classify-failure.ts b/packages/agent-runner/src/classify-failure.ts
new file mode 100644
index 0000000..6fa72b6
--- /dev/null
+++ b/packages/agent-runner/src/classify-failure.ts
@@ -0,0 +1,183 @@
+// Pure failure classification + bounded detail builder. Reads events through
+// an injected `EventProjection` so provider spellings never reach policy.
+
+import type { FailureCategory } from "@ship/workflow";
+
+import { LOCAL_RUN_CONTENTION_HINT } from "@ship/workflow";
+
+import type { AgentEvent, EventProjection } from "./event-projection.js";
+
+import { formatRunningToolAge } from "./formatters.js";
+import {
+  lastFailedToolCallDetail,
+  lastRunningToolCall,
+  runningToolAgeMs,
+  runningToolDetail,
+} from "./projection-helpers.js";
+
+const NEAR_CAP_DURATION_RATIO = 0.95;
+const COLLAPSE_DURATION_RATIO = 0.8;
+const RUNNING_TOOL_MIN_AGE_MS = 30_000;
+const MAX_FAILURE_DETAIL_CHARS = 512;
+const TRUNCATED_SUFFIX = "...";
+
+function boundFailureDetail(text: string): string {
+  if (text.length <= MAX_FAILURE_DETAIL_CHARS) return text;
+  const keep = MAX_FAILURE_DETAIL_CHARS - TRUNCATED_SUFFIX.length;
+  return `${text.slice(0, keep)}${TRUNCATED_SUFFIX}`;
+}
+
+export interface ClassifyFailureInput<E = AgentEvent> {
+  readonly projection: EventProjection<E>;
+  readonly sdkTerminalStatus?: string;
+  readonly isStoreContention?: boolean;
+  readonly thrownError?: boolean;
+  readonly durationMs?: number;
+  readonly maxRunDurationMs?: number;
+  readonly events: readonly E[];
+}
+
+export interface BuildFailureDetailInput<E = AgentEvent> {
+  readonly projection: EventProjection<E>;
+  readonly category: FailureCategory;
+  readonly sdkTerminalStatus?: string;
+  readonly durationMs?: number;
+  readonly maxRunDurationMs?: number;
+  readonly events: readonly E[];
+  readonly rawErrorMessage?: string;
+  readonly thrownErr?: unknown;
+}
+
+function isNearCap(durationMs: number | undefined, maxRunDurationMs: number | undefined): boolean {
+  if (durationMs === undefined || maxRunDurationMs === undefined) return false;
+  return durationMs >= NEAR_CAP_DURATION_RATIO * maxRunDurationMs;
+}
+
+function isCollapseDuration(
+  durationMs: number | undefined,
+  maxRunDurationMs: number | undefined,
+): boolean {
+  if (durationMs === undefined || maxRunDurationMs === undefined) return false;
+  return durationMs > COLLAPSE_DURATION_RATIO * maxRunDurationMs;
+}
+
+function normalizeSdkStatus(status: string | undefined): string | undefined {
+  if (status === undefined || status.length === 0) return undefined;
+  return status.toLowerCase();
+}
+
+function isExpiredStatus(status: string | undefined): boolean {
+  return normalizeSdkStatus(status) === "expired";
+}
+
+function agentCollapseOnRunningTool<E>(input: ClassifyFailureInput<E>): boolean {
+  const running = lastRunningToolCall(input.projection, input.events);
+  if (running === undefined) return false;
+  if (!isCollapseDuration(input.durationMs, input.maxRunDurationMs)) return false;
+  const age = runningToolAgeMs(
+    input.projection,
+    running,
+    input.events,
+    input.durationMs,
+    RUNNING_TOOL_MIN_AGE_MS,
+  );
+  if (age === undefined) return false;
+  return age > RUNNING_TOOL_MIN_AGE_MS;
+}
+
+export function classifyFailure<E = AgentEvent>(input: ClassifyFailureInput<E>): FailureCategory {
+  if (input.isStoreContention === true) return "contention";
+  if (input.thrownError === true) return "sdk-throw";
+  if (lastFailedToolCallDetail(input.projection, input.events) !== undefined) return "logic";
+  if (agentCollapseOnRunningTool(input)) return "agent-collapse-on-running-tool";
+  if (isExpiredStatus(input.sdkTerminalStatus)) return "timeout-near-cap";
+  if (isNearCap(input.durationMs, input.maxRunDurationMs)) return "timeout-near-cap";
+  return "unknown";
+}
+
+function thrownErrorMessage(err: unknown): string | undefined {
+  if (err instanceof Error && err.message.length > 0) return err.message;
+  if (typeof err === "string" && err.length > 0) return err;
+  return undefined;
+}
+
+function detailForContention<E>(input: BuildFailureDetailInput<E>): string {
+  const fromErr = thrownErrorMessage(input.thrownErr);
+  if (fromErr?.includes(LOCAL_RUN_CONTENTION_HINT) === true) return fromErr;
+  return LOCAL_RUN_CONTENTION_HINT;
+}
+
+function detailForSdkThrow<E>(input: BuildFailureDetailInput<E>): string {
+  const fromErr = thrownErrorMessage(input.thrownErr);
+  if (fromErr !== undefined) return fromErr;
+  if (input.rawErrorMessage !== undefined && input.rawErrorMessage.length > 0) {
+    return input.rawErrorMessage;
+  }
+  return "SDK error before terminal result";
+}
+
+function detailForLogic<E>(input: BuildFailureDetailInput<E>): string {
+  const detail = lastFailedToolCallDetail(input.projection, input.events);
+  if (detail !== undefined) return detail;
+  if (input.rawErrorMessage !== undefined && input.rawErrorMessage.length > 0) {
+    return input.rawErrorMessage;
+  }
+  return "tool_call failed";
+}
+
+function detailForAgentCollapse<E>(input: BuildFailureDetailInput<E>): string {
+  const running = lastRunningToolCall(input.projection, input.events);
+  if (running === undefined) return "agent stopped with a running tool_call";
+  const age =
+    runningToolAgeMs(
+      input.projection,
+      running,
+      input.events,
+      input.durationMs,
+      RUNNING_TOOL_MIN_AGE_MS,
+    ) ??
+    input.durationMs ??
+    0;
+  return runningToolDetail(running, age, formatRunningToolAge);
+}
+
+function detailForTimeoutNearCap<E>(input: BuildFailureDetailInput<E>): string {
+  const { durationMs, maxRunDurationMs } = input;
+  const capPart =
+    maxRunDurationMs !== undefined
+      ? `duration ${formatRunningToolAge(durationMs ?? 0)} (cap ${formatRunningToolAge(maxRunDurationMs)})`
+      : `duration ${formatRunningToolAge(durationMs ?? 0)}`;
+  if (isExpiredStatus(input.sdkTerminalStatus)) {
+    return `SDK status expired; ${capPart}`;
+  }
+  return capPart;
+}
+
+function detailForUnknown<E>(input: BuildFailureDetailInput<E>): string {
+  if (input.rawErrorMessage !== undefined && input.rawErrorMessage.length > 0) {
+    return input.rawErrorMessage;
+  }
+  const fromErr = thrownErrorMessage(input.thrownErr);
+  if (fromErr !== undefined) return fromErr;
+  if (input.sdkTerminalStatus !== undefined && input.sdkTerminalStatus.length > 0) {
+    return `SDK status ${input.sdkTerminalStatus}`;
+  }
+  return "no classification signals";
+}
+
+const DETAIL_BUILDERS: Record<FailureCategory, <E>(input: BuildFailureDetailInput<E>) => string> = {
+  contention: detailForContention,
+  "timeout-near-cap": detailForTimeoutNearCap,
+  "agent-collapse-on-running-tool": detailForAgentCollapse,
+  "sdk-throw": detailForSdkThrow,
+  logic: detailForLogic,
+  unknown: detailForUnknown,
+};
+
+export function buildFailureDetail<E = AgentEvent>(input: BuildFailureDetailInput<E>): string {
+  return boundFailureDetail(DETAIL_BUILDERS[input.category](input));
+}
+
+export function formatClassifiedErrorMessage(category: FailureCategory, detail: string): string {
+  return `${category}; ${detail}`;
+}
